code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, Button, icon } from 'decantr/components';

code.example:
function TierUpgradeCard({ tier, isCurrentTier, onUpgrade }) {
  const { div, h3, span, p, ul, li } = tags;

  return Card({ class: css(`_flex _col _w[320px] ${tier.highlighted ? '_borderprimary _border2' : ''}`) },
    div({ class: css('_p6 _flex _col _gap3') },
      div({ class: css('_flex _aic _gap2') },
        h3({ class: css('_heading4') }, tier.name),
        tier.highlighted ? Badge({ variant: 'primary', size: 'xs' }, 'Popular') : null
      ),
      div({ class: css('_flex _aic _baseline _gap1') },
        span({ class: css('_heading2') }, tier.price === 0 ? 'Free' : `$${tier.price}`),
        tier.price > 0 ? span({ class: css('_textsm _fgmuted') }, '/mo') : null
      ),
      p({ class: css('_bodysm _fgmuted') }, tier.description)
    ),
    div({ class: css('_px6 _pb6 _flex _col _gap2 _flex1') },
      ul({ class: css('_flex _col _gap2 _list-none _p0 _m0') },
        ...tier.features.map(feature =>
          li({ class: css('_flex _aic _gap2 _textsm') },
            icon('check', { size: '0.875rem', class: css('_fgsuccess') }),
            span({}, feature)
          )
        )
      )
    ),
    div({ class: css('_p6 _pt0') },
      Button({
        variant: isCurrentTier ? 'outline' : 'primary',
        size: 'md',
        class: css('_wfull'),
        disabled: isCurrentTier,
        onclick: () => onUpgrade(tier.id)
      }, isCurrentTier ? 'Current Plan' : `Upgrade to ${tier.name}`)
    )
  );
}

